$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_896e1fd6ab19d8bbd2f58f989fbaac76'] = 'Días de retención para estadísticas de conexiones';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Las filas anteriores a este valor se eliminarán de connections, connections_source y connections_page.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Introduzca el número de días durante los que deben conservarse las estadísticas brutas de visitantes de PrestaShop. Ejemplo: 60 significa que el módulo conserva los últimos 60 días y elimina registros más antiguos de ps_connections, ps_connections_source y ps_connections_page. No establezca 1 salvo que esté seguro de que no necesita estadísticas recientes.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Tamaño del lote';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Número máximo de conexiones procesadas en un lote.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Introduzca cuántos registros principales de conexión pueden procesarse en un lote interno. Los valores pequeños son más seguros en hosting débil pero requieren más ejecuciones cron. Los valores grandes limpian más rápido pero pueden mantener bloqueos de base de datos durante más tiempo. Valor inicial recomendado: 1000 a 5000; aumente solo después de probar el tiempo de ejecución.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Máximo de lotes por ejecución';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Limita cuánto trabajo puede hacer una ejecución cron.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Introduzca cuántos lotes pueden ejecutarse durante una ejecución cron. El total posible de registros principales de conexión eliminados por ejecución es aproximadamente Tamaño del lote multiplicado por Máximo de lotes por ejecución. Ejemplo: 5000 y 10 significa hasta unos 50000 registros principales en una ejecución cron. Reduzca este valor si la tienda se ralentiza durante la limpieza.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'Vaciar ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Vacía la caché del bloque de búsqueda facetada/layered mediante TRUNCATE TABLE. MySQL/MariaDB recrea la tabla vacía.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Actívelo solo si ps_layered_filter_block crece demasiado o contiene caché obsoleta de búsqueda facetada. No elimina productos, categorías ni el índice de precios layered. Después de limpiar, PrestaShop o el módulo de búsqueda facetada puede reconstruir esta caché cuando sea necesario.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Agregar estadísticas de fuentes de tráfico antes de eliminar';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Guarda estadísticas diarias resumidas de fuentes de tráfico antes de eliminar filas brutas.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Cuando está activado, el módulo guarda un pequeño resumen diario antes de eliminar estadísticas brutas de PrestaShop. Conserva recuentos como visitas, páginas vistas, dominio de origen y valores UTM. No guarda direcciones IP, URL completas de referencia ni cadenas user-agent. Desactívelo si solo desea eliminar y no necesita resúmenes históricos de fuentes.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Días de retención de estadísticas agregadas';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Cuánto tiempo debe conservarse la pequeña tabla de resumen diario.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Introduzca cuántos días deben permanecer los resúmenes agregados de tráfico en la tabla del módulo. Ejemplo: 730 conserva unos dos años de resúmenes diarios. Este ajuste solo afecta a la tabla ps_jooim_dbcleaner_traffic_daily, no a las tablas estadísticas originales de PrestaShop.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Tiempo de bloqueo obsoleto en segundos';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Protección contra dos procesos de limpieza ejecutándose al mismo tiempo.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2c1824ea38ec688698a26f01a46e6b16'] = 'Introduzca el número de segundos tras los cuales un bloqueo de limpieza sin finalizar se considera abandonado. Esto protege la base de datos de dos ejecuciones cron simultáneas. Valor recomendado: 7200. Redúzcalo solo si su cron termina siempre rápido.';
